using System;
using UnityEngine;

namespace AssetRenamer.Editor
{
    /// <summary>
    /// Tool artwork baked into the assembly as base64 so the visuals cannot be
    /// swapped by replacing a loose image file in the package.
    /// </summary>
    internal static class EmbeddedArt
    {
        #region Public

        public static Texture2D LoadBanner() => Decode(BANNER_BASE64);

        public static Texture2D LoadIcon() => Decode(ICON_BASE64);

        #endregion


        #region Tools and Utilities

        private static Texture2D Decode(string base64)
        {
            byte[] bytes = Convert.FromBase64String(base64);
            Texture2D tex = new Texture2D(2, 2, TextureFormat.RGBA32, mipChain: false);
            tex.LoadImage(bytes);
            tex.hideFlags = HideFlags.HideAndDontSave;
            return tex;
        }

        #endregion


        #region Private and Protected

        private const string BANNER_BASE64 = "";
        private const string ICON_BASE64 = "";

        #endregion
    }
}
